AND si.created_at >= #{fromDateTime}
AND si.created_at < #{toDateTimeExclusive}

    AND si.status = #{status}


    AND si.category_code = #{categoryCode}


    AND (
        LOWER(si.title) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(si.content_text) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(COALESCE(u.name, u.username)) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(u.username) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(u.email) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(si.inquiry_no) LIKE CONCAT('%', LOWER(#{keyword}), '%')
    )

mapper.select:
